       public int maLookback( int optInTimePeriod, MAType optInMAType )
       {
          int retValue;
          if( (optInTimePeriod<=1) ) {
             return 0 ;
          }
          switch( optInMAType )
          {
          case MAType.Sma:
             retValue = smaLookback(optInTimePeriod);
             break;
          case MAType.Ema:
             retValue = emaLookback(optInTimePeriod);
             break;
          case MAType.Wma:
             retValue = wmaLookback(optInTimePeriod);
             break;
          case MAType.Dema:
             retValue = demaLookback(optInTimePeriod);
             break;
          case MAType.Tema:
             retValue = temaLookback(optInTimePeriod);
             break;
          case MAType.Trima:
             retValue = trimaLookback(optInTimePeriod);
             break;
          case MAType.Kama:
             retValue = kamaLookback(optInTimePeriod);
             break;
          case MAType.Mama:
             retValue = mamaLookback(0.5, 0.05);
             break;
          case MAType.T3:
             retValue = t3Lookback(optInTimePeriod, 0.7);
             break;
          default:
             retValue = 0;
             break;
          }
          return retValue ;

       }
       public RetCode ma( int startIdx,
                          int endIdx,
                          double inReal[],
                          int optInTimePeriod,
                          MAType optInMAType,
                          MInteger outBegIdx,
                          MInteger outNBElement,
                          double outReal[] )
       {
          double[] dummyBuffer;
          RetCode retCode;
          int nbElement = 0;
          int outIdx = 0;
          int todayIdx = 0;
          if( startIdx < 0 ) {
             return RetCode.OutOfRangeStartIndex ;
          }
          if( (endIdx < 0) || (endIdx < startIdx)) {
             return RetCode.OutOfRangeEndIndex ;
          }
          if( (optInTimePeriod==1) ) {
             nbElement = ((endIdx-startIdx)+1);
             outNBElement.value = nbElement;
             for( todayIdx = startIdx, outIdx = 0; (outIdx<nbElement); outIdx += 1, todayIdx += 1 ) {
                outReal[outIdx] = inReal[todayIdx];
             }
             outBegIdx.value = startIdx;
             return RetCode.Success ;
          }
          switch( optInMAType )
          {
          case MAType.Sma:
             retCode = sma(startIdx, endIdx, inReal, optInTimePeriod, outBegIdx, outNBElement, outReal);
             break;
          case MAType.Ema:
             retCode = ema(startIdx, endIdx, inReal, optInTimePeriod, outBegIdx, outNBElement, outReal);
             break;
          case MAType.Wma:
             retCode = wma(startIdx, endIdx, inReal, optInTimePeriod, outBegIdx, outNBElement, outReal);
             break;
          case MAType.Dema:
             retCode = dema(startIdx, endIdx, inReal, optInTimePeriod, outBegIdx, outNBElement, outReal);
             break;
          case MAType.Tema:
             retCode = tema(startIdx, endIdx, inReal, optInTimePeriod, outBegIdx, outNBElement, outReal);
             break;
          case MAType.Trima:
             retCode = trima(startIdx, endIdx, inReal, optInTimePeriod, outBegIdx, outNBElement, outReal);
             break;
          case MAType.Kama:
             retCode = kama(startIdx, endIdx, inReal, optInTimePeriod, outBegIdx, outNBElement, outReal);
             break;
          case MAType.Mama:
             dummyBuffer = new double[(int)((((endIdx-startIdx)+1)*1))];
             retCode = mama(startIdx, endIdx, inReal, 0.5, 0.05, outBegIdx, outNBElement, outReal, dummyBuffer);
             break;
          case MAType.T3:
             retCode = t3(startIdx, endIdx, inReal, optInTimePeriod, 0.7, outBegIdx, outNBElement, outReal);
             break;
          default:
             retCode = RetCode.BadParam;
             break;
          }
          return retCode ;
       }
